# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit
import URLHandling

class UniversalLinkHandler: NSObject, URLHandler {
    
    var handlingCompletion: ((UIViewController) -> Void)?
    
    func canHandle(_ url: URL) -> Bool {
        return url.scheme == "https" && url.host == "myapp.com" && url.path == "/reset-password"
    }
    
    func handle(_ url: URL) {
        if let queryItems = url.queryItems,
           let token = queryItems.first(where: { $0.name == "token" })?.value {
            performSegue(withIdentifier: "toResetPassword", sender: nil)
            
            if let resetPasswordVC = presentingViewController as? ResetPasswordViewController {
                resetPasswordVC.token = token
            }
        } else {
            print("Invalid URL format")
        }
    }
}